#include <string>
#include <algorithm>

std::string solve(long long n) {
    long long n_squared = n * n;
    std::string hex_part;
    if (n_squared == 0) {
        hex_part = "0";
    } else {
        while (n_squared > 0) {
            int remainder = n_squared % 16;
            if (remainder < 10) {
                hex_part += '0' + remainder;
            } else {
                hex_part += 'A' + (remainder - 10);
            }
            n_squared /= 16;
        }
        std::reverse(hex_part.begin(), hex_part.end());
    }

    long long n_cubed = n * n * n;
    std::string base36_part;
    if (n_cubed == 0) {
        base36_part = "0";
    } else {
        while (n_cubed > 0) {
            int remainder = n_cubed % 36;
            if (remainder < 10) {
                base36_part += '0' + remainder;
            } else {
                base36_part += 'A' + (remainder - 10);
            }
            n_cubed /= 36;
        }
        std::reverse(base36_part.begin(), base36_part.end());
    }

    return hex_part + base36_part;
}
